long long pw(long long a, long long b, long long m) {
    long long res = 1; a %= m;
    while (b) { if (b & 1) res = res * a % m; a = a * a % m; b >>= 1; }
    return res;
}
long long inv(long long a, long long m) { return pw(a, m - 2, m); }

