void solve(int row, vector<int>& col, vector<bool>& cu, vector<bool>& cl, vector<bool>& cr) {
    if (row == N) { ans++; return; }
    for (int c = 0; c < N; c++) {
        if (cu[c] || cl[row-c+N] || cr[row+c]) continue;
        cu[c] = cl[row-c+N] = cr[row+c] = true;
        col[row] = c;
        solve(row + 1, col, cu, cl, cr);
        cu[c] = cl[row-c+N] = cr[row+c] = false;
    }
}

